actions.script:
import org.moqui.context.ExecutionContext
ExecutionContext ec = context.ec
def appList = []

// Get all component names
def componentNames = ec.entity.query("moqui.basic.Enumeration")
    .condition("enumTypeId", "ComponentType").list()*.enumId

// Also check file system for components with 'spec' or 'specs' folders
// We check runtime/component/* and runtime/component/*/overlay/*
def componentBaseDir = new File(ec.factory.runtimePath, "component")
if (componentBaseDir.exists()) {
    componentBaseDir.eachDir { File compDir ->
        def hasSpec = new File(compDir, "spec").exists() || new File(compDir, "specs").exists()
        if (!hasSpec) {
            def overlayDir = new File(compDir, "overlay")
            if (overlayDir.exists()) {
                hasSpec = new File(overlayDir, "spec").exists() || new File(overlayDir, "specs").exists()
            }
        }

        if (hasSpec) {
            def label = compDir.name.capitalize()
            appList.add([label: label, value: compDir.name])
        }
    }
}

context.apps = appList
